// Lambda@Edge function for CloudFront origin response events
exports.handler = async (event) => {
  const request = event.Records[0].cf.request;
  const response = event.Records[0].cf.response;

  // Get the custom headers set by the viewer request function
  const injectionPoints = request.headers['injection-points'];
  const content = request.headers['content'];

  // Parse the HTML response and insert content at specified locations
  const htmlResponse = await parseHTML(response.body);
  const injectedHtml = await injectContent(htmlResponse, injectionPoints, content);

  // Return the modified HTML response
  return {
    status: '200',
    body: injectedHtml,
    headers: {
      'content-type': 'text/html; charset=utf-8'
    }
  };
};

// Parse HTML response and insert content at specified locations
async function parseHTML(body) {
  const parser = new DOMParser();
  const doc = parser.parseFromString(body, 'text/html');
  return doc;
}

// Inject content into the HTML document at specified locations
async function injectContent(doc, injectionPoints, content) {
  // Get the injection points from the custom headers
  const injectionPointList = JSON.parse(injectionPoints);

  // Iterate over each injection point and insert the content
  for (const injectionPoint of injectionPointList) {
    const element = doc.querySelector(injectionPoint.selector);
    if (element) {
      element.innerHTML += content;
    } else {
      console.log(`Injection point not found: ${injectionPoint.selector}`);
    }
  }

  // Return the modified HTML document
  return doc.documentElement.outerHTML;
}